// Ribbingintie 109-11, Helsinki — 1980s omakotitalo
// 2-story wood-frame house, gable roof, ~12x10m footprint

// Foundation
const foundation = translate(box(12, 0.3, 10), 0, 0.15, 0);
scene.add(foundation, {material: "concrete", color: [0.55, 0.55, 0.52]});

// Ground floor walls
const gf_front = translate(box(12, 2.7, 0.2), 0, 1.65, -4.9);
scene.add(gf_front, {material: "wood", color: [0.76, 0.60, 0.42]});

const gf_back = translate(box(12, 2.7, 0.2), 0, 1.65, 4.9);
scene.add(gf_back, {material: "wood", color: [0.72, 0.56, 0.38]});

const gf_left = translate(box(0.2, 2.7, 10), -5.9, 1.65, 0);
scene.add(gf_left, {material: "wood", color: [0.68, 0.53, 0.35]});

const gf_right = translate(box(0.2, 2.7, 10), 5.9, 1.65, 0);
scene.add(gf_right, {material: "wood", color: [0.70, 0.55, 0.37]});

// First floor slab
const floor1 = translate(box(12, 0.25, 10), 0, 3.125, 0);
scene.add(floor1, {material: "concrete", color: [0.60, 0.60, 0.58]});

// Upper floor walls
const uf_front = translate(box(12, 2.7, 0.2), 0, 4.6, -4.9);
scene.add(uf_front, {material: "wood", color: [0.76, 0.60, 0.42]});

const uf_back = translate(box(12, 2.7, 0.2), 0, 4.6, 4.9);
scene.add(uf_back, {material: "wood", color: [0.72, 0.56, 0.38]});

const uf_left = translate(box(0.2, 2.7, 10), -5.9, 4.6, 0);
scene.add(uf_left, {material: "wood", color: [0.68, 0.53, 0.35]});

const uf_right = translate(box(0.2, 2.7, 10), 5.9, 4.6, 0);
scene.add(uf_right, {material: "wood", color: [0.70, 0.55, 0.37]});

// Gable roof — ~30deg pitch
const roof_left = translate(rotate(box(12.6, 0.08, 6.2), 0.52, 0, 0), 0, 7.5, -2.5);
scene.add(roof_left, {material: "metal", color: [0.25, 0.22, 0.20]});

const roof_right = translate(rotate(box(12.6, 0.08, 6.2), -0.52, 0, 0), 0, 7.5, 2.5);
scene.add(roof_right, {material: "metal", color: [0.25, 0.22, 0.20]});

// Front porch
const porch_post_l = translate(box(0.12, 2.5, 0.12), -1.0, 1.55, -5.8);
scene.add(porch_post_l, {material: "wood", color: [0.65, 0.50, 0.33]});

const porch_post_r = translate(box(0.12, 2.5, 0.12), 1.0, 1.55, -5.8);
scene.add(porch_post_r, {material: "wood", color: [0.65, 0.50, 0.33]});

const porch_roof = translate(rotate(box(2.8, 0.06, 1.4), 0.15, 0, 0), 0, 2.9, -5.5);
scene.add(porch_roof, {material: "metal", color: [0.30, 0.27, 0.25]});

const porch_floor = translate(box(2.4, 0.12, 1.2), 0, 0.36, -5.5);
scene.add(porch_floor, {material: "concrete", color: [0.58, 0.56, 0.54]});
